    uv -= 0.5; // Center UV (from -0.5 to 0.5)
    uv.x *= u_resolution.x / u_resolution.y; // Aspect ratio correction

    // Calculate radial distance from the center
    float dist = length(uv);

    // Harmonic wave parameters
    float freq1 = 20.0; // Frequency of the primary ripple
    float speed1 = 1.8; // Speed of the primary ripple
    float freq2 = 30.0; // Frequency of a secondary ripple layer
    float speed2 = 1.2; // Speed of the secondary ripple layer

    // Create a base sine wave, symmetrical around the center
    // This forms the "symmetrical sine coordinates" part of the hypothesis.
    float wave = sin(dist * freq1 - u_time * speed1);
    // Add a second wave for more organic complexity and subtle interaction
    wave += sin(dist * freq2 + u_time * speed2);
    wave *= 0.5; // Normalize amplitude to keep it within [-1, 1]

    // Exponential damping factor based on distance from center
    // This is the "slow, exponential damping factor" to "reduce visual friction".
    // It makes ripples fainter further away from the center.
    float dampingFactor = 4.5; // Controls how quickly the wave damps with distance
    float damping = exp(-dist * dampingFactor);

    // Apply damping to the wave's amplitude
    wave *= damping;

    // Map the damped wave value from [-1, 1] to [0, 1] for color mixing
    // This allows for a smooth transition between two colors.
    float normalizedWave = wave * 0.5 + 0.5;

