    vec3 colorHigh = vec3(0.4, 0.7, 1.0);    // Lighter blue-white

    // Mix the colors based on the normalized wave value
    vec3 finalColor = mix(colorLow, colorHigh, normalizedWave);

    // Final color output
    gl_FragColor = vec4(finalColor, 1.0);
