// Simplex Noise (from https://github.com/ashima/webgl-noise/blob/master/src/noise2D.glsl)
vec3 mod289(vec3 x) { return x - floor(x * (1.0 / 289.0)) * 289.0; }
vec2 mod289(vec2 x) { return x - floor(x * (1.0 / 289.0)) * 289.0; }
vec3 permute(vec3 x) { return mod289(((x*34.0)+1.0)*x); }

float snoise(vec2 v) {
  const vec4 C = vec4(0.211324865405187,  // (3.0-sqrt(3.0))/6.0
                      0.366025403784439,  // 0.5*(sqrt(3.0)-1.0)
                     -0.577350269189626,  // -1.0 + 2.0 * C.x
                      0.024390243902439); // 1.0 / 41.0
  vec2 i = floor(v + dot(v, C.yy) );
  vec2 x0 = v - i + dot(i, C.xx);
  vec2 i1 = (x0.x > x0.y) ? vec2(1.0, 0.0) : vec2(0.0, 1.0);
  vec4 x12 = x0.xyxy + C.xxzz;
  x12.xy -= i1;
  i = mod289(i);
  vec3 p = permute( permute( i.y + vec3(0.0, i1.y, 1.0 )) + i.x + vec3(0.0, i1.x, 1.0 ));
  vec3 m = max(0.5 - vec3(dot(x0,x0), dot(x12.xy,x12.xy), dot(x12.zw,x12.zw)), 0.0);
  m = m*m ;
  m = m*m ;
  vec3 x = 2.0 * fract(p * C.www) - 1.0;
  vec3 h = abs(x) - 0.5;
  vec3 ox = floor(x + 0.5);
  vec3 a0 = x - ox;
  m *= 1.79284291400159 - 0.85373472095314 * ( a0*a0 + h*h );
  vec3 g;
  g.x  = a0.x  * x0.x  + h.x  * x0.y;
  g.yz = a0.yz * x12.xz + h.yz * x12.yw;
  return 130.0 * dot(m, g);
}

void main() {
    vec2 uv = gl_FragCoord.xy / u_resolution.xy;
    uv = uv * 2.0 - 1.0; // Scale to [-1, 1]
    uv.x *= u_resolution.x / u_resolution.y; // Aspect ratio correction

    // 1. Damped Symmetrical Sine Wave
    // Combine two sine waves for a more complex, oscillating base pattern
    float wave_x = sin(uv.x * 7.0 + u_time * 0.6);
    float wave_y = cos(uv.y * 7.0 + u_time * 0.4);
    float s_wave_field = wave_x * wave_y;

    // Apply strong damping based on distance from the center, creating a localized nexus
    float dist_from_center = length(uv);
    s_wave_field *= exp(-dist_from_center * 2.5);

    // 2. Feedback Loop: s_wave_field modulates snoise frequency and amplitude
    // Frequency modulation: more intense wave field means higher frequency noise
    float freq_mod = s_wave_field * 8.0; 

    // Amplitude modulation: stronger wave field means higher amplitude noise
    // A base amplitude ensures noise is always visible, varying more with s_wave_field
    float amp_mod = 0.6 + abs(s_wave_field) * 0.7; 

    // Base coordinates for noise, with a gentle time-based movement
    vec2 base_noise_coords = uv * (12.0 + freq_mod);
    vec2 time_offset = vec2(u_time * 0.08, u_time * 0.06);

    // Multiple octaves of Simplex Noise for complex organic flow
    float total_noise = 0.0;
    float amplitude = 1.0;
    float frequency = 1.0;

    for (int i = 0; i < 3; ++i) { // Sum 3 octaves
        total_noise += snoise(base_noise_coords * frequency + time_offset * float(i+1) * 0.5) * amplitude;
        amplitude *= 0.5; // Decrease amplitude for higher octaves
        frequency *= 2.0; // Increase frequency for higher octaves
    }

    total_noise *= amp_mod; // Apply the overall amplitude modulation

    // Normalize noise to [0, 1] range for color mapping
    // snoise returns in [-1, 1], so total_noise will be in a larger range.
    // A divisor of 0.2 maps the expected range of roughly [-2.275, 2.275] to [~0.045, ~0.955]
    total_noise = total_noise * 0.2 + 0.5; 
    total_noise = clamp(total_noise, 0.0, 1.0); // Ensure it stays within [0, 1]

    // Color mapping for "Chaotic Serenity Nexus"
    // Blend primary colors based on noise, then introduce s_wave_field influence
    vec3 col1 = vec3(0.05, 0.15, 0.25); // Deep blue-green for backgrounds
    vec3 col2 = vec3(0.8, 0.4, 0.1);    // Warm orange for highlights
    vec3 col3 = vec3(0.3, 0.7, 0.6);    // Soft teal for nexus core
    vec3 col4 = vec3(0.9, 0.9, 0.8);    // Light almost white for subtle glows

    vec3 final_color = mix(col1, col2, total_noise);

    // Introduce s_wave_field influence directly for the "nexus" effect
    // Stronger wave areas (high abs value) pull colors towards teal and subtle whites
    float s_wave_influence = abs(s_wave_field);
    final_color = mix(final_color, col3, s_wave_influence * 0.7); 
    final_color = mix(final_color, col4, s_wave_influence * 0.3 * (1.0 - total_noise)); 

    // Final subtle adjustment for overall tinting based on wave direction
    final_color += s_wave_field * 0.05; 

    gl_FragColor = vec4(final_color, 1.0);
}
